package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.quality.*;import com.chaobo.scm.supplier.application.shared.CommandResult;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.*;import org.springframework.security.core.annotation.*;import org.springframework.security.oauth2.jwt.*;import org.springframework.web.bind.annotation.*;import java.time.*;
@RestController @RequestMapping("/api/supplier/v1/quality-issues") public class SupplierQualityIssueController{private final SupplierQualityIssueApplicationService service;private final CommandContextFactory contexts;public SupplierQualityIssueController(SupplierQualityIssueApplicationService service,CommandContextFactory contexts){this.service=service;this.contexts=contexts;}@GetMapping public ApiResponse<PageResult<SupplierQualityIssueView>> page(@RequestParam(required=false)Long supplierId,@RequestParam(required=false)Integer status,@RequestParam(required=false)Integer severity,@RequestParam(defaultValue="1")int pageNo,@RequestParam(defaultValue="20")int pageSize,@AuthenticationPrincipal Jwt jwt,HttpServletRequest request){return ApiResponse.success(service.page(supplierId,scope(jwt),status,severity,pageNo,pageSize),request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}@GetMapping("/{id}")public ApiResponse<SupplierQualityIssueView> detail(@PathVariable long id,@AuthenticationPrincipal Jwt jwt,HttpServletRequest r){return ApiResponse.success(service.detail(id,scope(jwt)),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}@PostMapping public ApiResponse<CommandResult> create(@Valid @RequestBody Create b,HttpServletRequest r,Authentication a){return ok(service.create(b.supplierId(),b.sourceType(),b.sourceNo(),b.issueType(),b.severity(),b.description(),contexts.create(r,a)),r);}@PostMapping("/{id}/request-rectification")public ApiResponse<CommandResult> request(@PathVariable long id,@Valid @RequestBody Rectify b,HttpServletRequest r,Authentication a){return ok(service.requestRectification(id,b.version(),b.deadline(),contexts.create(r,a)),r);}@PostMapping("/{id}/submit-plan")public ApiResponse<CommandResult> submit(@PathVariable long id,@Valid @RequestBody Plan b,HttpServletRequest r,Authentication a){return ok(service.submitPlan(id,b.version(),b.plan(),contexts.create(r,a)),r);}@PostMapping("/{id}/verify")public ApiResponse<CommandResult> verify(@PathVariable long id,@Valid @RequestBody Verify b,HttpServletRequest r,Authentication a){return ok(service.verify(id,b.version(),b.passed(),b.comment(),contexts.create(r,a)),r);}private ApiResponse<CommandResult> ok(CommandResult v,HttpServletRequest r){return ApiResponse.success(v,r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}private Long scope(Jwt j){Number n=j.hasClaim("supplier_id")?j.getClaim("supplier_id"):null;return n==null?null:n.longValue();}public record Create(@Positive long supplierId,@NotBlank String sourceType,String sourceNo,@NotBlank String issueType,@Min(1)@Max(4)int severity,@NotBlank String description){}public record Rectify(@PositiveOrZero int version,@NotNull OffsetDateTime deadline){}public record Plan(@PositiveOrZero int version,@NotBlank String plan){}public record Verify(@PositiveOrZero int version,boolean passed,@NotBlank String comment){}}
